"use client";

import { useEffect, useMemo } from "react";
import { BarChart3, BadgeCheck, TrendingUp, Users, Wallet, XCircle } from "lucide-react";
import { useSubscriptionStore } from "@/features/subscription/store/use-subscription-store";

const MONTHS_LABELS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

function MiniBarChart({ data, color = "#6f9b7f" }: { data: number[]; color?: string }) {
  const max = Math.max(...data, 1);
  return (
    <div className="flex h-16 items-end gap-1">
      {data.map((v, i) => (
        <div key={i} className="flex flex-1 flex-col items-center gap-1">
          <div
            className="w-full rounded-t-sm"
            style={{
              height: `${Math.max((v / max) * 100, 4)}%`,
              backgroundColor: color,
              opacity: v === 0 ? 0.2 : 1,
            }}
          />
        </div>
      ))}
    </div>
  );
}

function StatRow({ label, value, sub }: { label: string; value: string | number; sub?: string }) {
  return (
    <div className="flex items-center justify-between py-2">
      <p className="text-sm text-muted-foreground">{label}</p>
      <div className="text-right">
        <p className="text-sm font-semibold text-foreground">{value}</p>
        {sub && <p className="text-[10px] text-muted-foreground">{sub}</p>}
      </div>
    </div>
  );
}

export default function AdminAnalyticsPage() {
  const requests = useSubscriptionStore((state) => state.requests);
  const loadAdminRequests = useSubscriptionStore((state) => state.loadAdminRequests);
  const isLoading = useSubscriptionStore((state) => state.isLoading);

  useEffect(() => {
    void loadAdminRequests();
  }, [loadAdminRequests]);

  const stats = useMemo(() => {
    const approved = requests.filter((r) => r.status === "approved");
    const rejected = requests.filter((r) => r.status === "rejected");
    const pending = requests.filter((r) => r.status === "pending");
    const totalRevenue = approved.reduce((s, r) => s + r.amount, 0);
    const avgRevenue = approved.length ? totalRevenue / approved.length : 0;
    const approvalRate = requests.length
      ? Math.round((approved.length / requests.length) * 100)
      : 0;

    // Monthly revenue for the last 12 months
    const now = new Date();
    const monthlyRevenue = Array.from({ length: 12 }, (_, i) => {
      const d = new Date(now.getFullYear(), now.getMonth() - 11 + i, 1);
      const monthStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
      return approved
        .filter((r) => r.submittedAt.startsWith(monthStr))
        .reduce((sum, r) => sum + r.amount, 0);
    });

    const monthlySubmissions = Array.from({ length: 12 }, (_, i) => {
      const d = new Date(now.getFullYear(), now.getMonth() - 11 + i, 1);
      const monthStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
      return requests.filter((r) => r.submittedAt.startsWith(monthStr)).length;
    });

    // Most active month
    const peakRevIdx = monthlyRevenue.indexOf(Math.max(...monthlyRevenue));
    const peakMonth = MONTHS_LABELS[(now.getMonth() - 11 + peakRevIdx + 12) % 12];

    // Plan duration breakdown
    const durationBreakdown: Record<number, number> = {};
    approved.forEach((r) => {
      durationBreakdown[r.months] = (durationBreakdown[r.months] ?? 0) + 1;
    });

    return {
      totalRevenue,
      avgRevenue,
      approvedCount: approved.length,
      rejectedCount: rejected.length,
      pendingCount: pending.length,
      totalRequests: requests.length,
      approvalRate,
      monthlyRevenue,
      monthlySubmissions,
      peakMonth,
      durationBreakdown,
    };
  }, [requests]);

  const last12Labels = Array.from({ length: 12 }, (_, i) => {
    const now = new Date();
    const d = new Date(now.getFullYear(), now.getMonth() - 11 + i, 1);
    return MONTHS_LABELS[d.getMonth()];
  });

  return (
    <div className="space-y-5 pb-10">
      {/* Header */}
      <div className="rounded-2xl border border-border/60 bg-surface p-5">
        <p className="text-[11px] uppercase tracking-[0.2em] text-muted-foreground">Admin Console</p>
        <h2 className="mt-1 text-xl font-bold text-foreground">Analytics & Reports</h2>
        <p className="mt-1 text-xs text-muted-foreground">Revenue trends, conversion rates, and subscription insights.</p>
      </div>

      {/* Top KPIs */}
      <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
        {[
          { label: "Total Revenue", value: `৳${stats.totalRevenue.toLocaleString()}`, icon: Wallet, color: "text-primary bg-primary/10" },
          { label: "Active Pro Users", value: stats.approvedCount, icon: BadgeCheck, color: "text-emerald-700 bg-emerald-100 dark:bg-emerald-950/40 dark:text-emerald-400" },
          { label: "Approval Rate", value: `${stats.approvalRate}%`, icon: TrendingUp, color: "text-sky-700 bg-sky-100 dark:bg-sky-950/40 dark:text-sky-400" },
          { label: "Total Requests", value: stats.totalRequests, icon: Users, color: "text-muted-foreground bg-border/40" },
        ].map((kpi) => (
          <div key={kpi.label} className="rounded-2xl border border-border/60 bg-surface p-4">
            <div className={`mb-2 flex h-8 w-8 items-center justify-center rounded-xl ${kpi.color}`}>
              <kpi.icon size={16} />
            </div>
            <p className="text-xl font-bold text-foreground">{kpi.value}</p>
            <p className="text-[10px] text-muted-foreground">{kpi.label}</p>
          </div>
        ))}
      </div>

      {/* Revenue Chart */}
      <div className="rounded-2xl border border-border/60 bg-surface p-5">
        <div className="mb-3 flex items-center justify-between">
          <div>
            <h3 className="text-sm font-semibold text-foreground">Monthly Revenue</h3>
            <p className="text-[10px] text-muted-foreground">Last 12 months (BDT)</p>
          </div>
          {stats.peakMonth && <p className="text-xs text-muted-foreground">Peak: {stats.peakMonth}</p>}
        </div>
        {isLoading ? (
          <div className="h-16 animate-pulse rounded-lg bg-border/30" />
        ) : (
          <MiniBarChart data={stats.monthlyRevenue} color="var(--primary)" />
        )}
        <div className="mt-1 flex justify-between">
          {last12Labels.map((label, i) => (
            <span key={i} className="text-[9px] text-muted-foreground">{label}</span>
          ))}
        </div>
      </div>

      {/* Submissions Chart */}
      <div className="rounded-2xl border border-border/60 bg-surface p-5">
        <div className="mb-3">
          <h3 className="text-sm font-semibold text-foreground">Monthly Submissions</h3>
          <p className="text-[10px] text-muted-foreground">All subscription requests (last 12 months)</p>
        </div>
        {isLoading ? (
          <div className="h-16 animate-pulse rounded-lg bg-border/30" />
        ) : (
          <MiniBarChart data={stats.monthlySubmissions} color="#8a83ab" />
        )}
        <div className="mt-1 flex justify-between">
          {last12Labels.map((label, i) => (
            <span key={i} className="text-[9px] text-muted-foreground">{label}</span>
          ))}
        </div>
      </div>

      {/* Key Metrics */}
      <div className="rounded-2xl border border-border/60 bg-surface p-5">
        <h3 className="mb-1 text-sm font-semibold text-foreground">Key Metrics</h3>
        <div className="divide-y divide-border/40">
          <StatRow label="Average revenue per user (ARPU)" value={`৳${stats.avgRevenue.toFixed(0)}`} />
          <StatRow
            label="Approval rate"
            value={`${stats.approvalRate}%`}
            sub={`${stats.approvedCount} approved / ${stats.totalRequests} total`}
          />
          <StatRow label="Pending review" value={stats.pendingCount} sub="Awaiting admin action" />
          <StatRow label="Rejected requests" value={stats.rejectedCount} sub="Payment not verified" />
        </div>
      </div>

      {/* Plan Duration Breakdown */}
      {Object.keys(stats.durationBreakdown).length > 0 && (
        <div className="rounded-2xl border border-border/60 bg-surface p-5">
          <h3 className="mb-3 text-sm font-semibold text-foreground">Plan Duration Breakdown</h3>
          <div className="space-y-2">
            {Object.entries(stats.durationBreakdown)
              .sort(([a], [b]) => Number(a) - Number(b))
              .map(([months, count]) => {
                const pct = Math.round((count / stats.approvedCount) * 100);
                return (
                  <div key={months}>
                    <div className="flex items-center justify-between text-xs">
                      <span className="text-muted-foreground">
                        {months} month{Number(months) !== 1 ? "s" : ""}
                      </span>
                      <span className="font-semibold text-foreground">
                        {count} ({pct}%)
                      </span>
                    </div>
                    <div className="mt-1 h-1.5 w-full rounded-full bg-border/40">
                      <div
                        className="h-full rounded-full bg-primary transition-all"
                        style={{ width: `${pct}%` }}
                      />
                    </div>
                  </div>
                );
              })}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {
  Bell,
  CheckCircle2,
  ChevronRight,
  ExternalLink,
  Info,
  Loader2,
  Lock,
  Save,
  Settings,
  Shield,
  AlertCircle,
} from "lucide-react";
import { useConfigStore } from "@/lib/config/use-config-store";

const SECURITY_ITEMS = [
  { icon: Shield, label: "Admin Access", desc: "Controlled via Appwrite user labels. Add 'admin' label in Appwrite console to grant access." },
  { icon: Lock, label: "Middleware Route Guard", desc: "All /admin/* routes are protected via middleware cookie checks (hw_session + hw_admin)." },
  { icon: Bell, label: "Activity Logging", desc: "All admin actions (approve/reject) are logged to the admin_logs Appwrite collection." },
];

export default function AdminSettingsPage() {
  const [activeSection, setActiveSection] = useState<"config" | "security" | "appwrite">("config");
  const [saved, setSaved] = useState(false);

  const { config, isLoading, error, loadConfig, saveConfig } = useConfigStore();
  const [formData, setFormData] = useState(config);

  useEffect(() => {
    void loadConfig();
  }, [loadConfig]);

  useEffect(() => {
    setFormData(config);
  }, [config]);

  async function handleSave(e: React.FormEvent) {
    e.preventDefault();
    try {
      await saveConfig(formData);
      setSaved(true);
      setTimeout(() => setSaved(false), 2000);
    } catch (err) {
      // Error handled by store
    }
  }

  function handleNumberChange(key: keyof typeof config, value: string) {
    const num = parseInt(value, 10);
    setFormData((prev) => ({ ...prev, [key]: isNaN(num) ? 0 : num }));
  }

  return (
    <div className="space-y-5 pb-10">
      {/* Header */}
      <div className="rounded-2xl border border-border/60 bg-surface p-5">
        <div className="flex items-center gap-2">
          <Settings size={18} className="text-primary" />
          <div>
            <p className="text-[11px] uppercase tracking-[0.2em] text-muted-foreground">Admin Console</p>
            <h2 className="text-xl font-bold text-foreground">Settings</h2>
          </div>
        </div>
        <p className="mt-1 text-xs text-muted-foreground">
          Platform configuration, security details, and Appwrite integration info.
        </p>
      </div>

      {/* Section Tabs */}
      <div className="flex gap-1.5 overflow-x-auto">
        {(["config", "security", "appwrite"] as const).map((s) => (
          <button
            key={s}
            type="button"
            onClick={() => setActiveSection(s)}
            className={`shrink-0 rounded-xl px-4 py-2 text-xs font-medium capitalize transition-all ${
              activeSection === s
                ? "bg-primary text-white"
                : "border border-border/60 text-muted-foreground hover:bg-surface hover:text-foreground"
            }`}
          >
            {s === "config" ? "Configuration" : s === "security" ? "Security" : "Appwrite"}
          </button>
        ))}
      </div>

      {/* Configuration */}
      {activeSection === "config" && (
        <form onSubmit={handleSave} className="rounded-2xl border border-border/60 bg-surface p-5 space-y-4">
          <div>
            <h3 className="text-sm font-semibold text-foreground">Platform Configuration</h3>
            <p className="mt-0.5 text-xs text-muted-foreground">
              These values apply globally and automatically reflect on user dashboards.
            </p>
          </div>

          {error && (
            <div className="flex items-start gap-2 rounded-xl border border-red-200 bg-red-50 p-3 text-xs text-red-700 dark:border-red-900/50 dark:bg-red-950/40 dark:text-red-400">
              <AlertCircle size={14} className="mt-0.5 shrink-0" />
              <div className="flex-1">
                <p className="font-semibold">Configuration Error</p>
                <p>{error}</p>
              </div>
            </div>
          )}

          <div className="space-y-3">
            <label className="block">
              <span className="mb-1 block text-xs font-medium text-foreground">bKash Receive Number</span>
              <input
                type="text"
                required
                value={formData.bkashNumber}
                onChange={(e) => setFormData((prev) => ({ ...prev, bkashNumber: e.target.value }))}
                placeholder="01XXXXXXXXX"
                className="h-10 w-full rounded-xl border border-border bg-background px-3 text-sm focus:border-primary focus:outline-none"
              />
              <span className="mt-1 block text-[10px] text-muted-foreground">Number users send payment to</span>
            </label>

            <div className="grid grid-cols-2 gap-3">
              <label className="block">
                <span className="mb-1 block text-xs font-medium text-foreground">Pro Price (BDT/month)</span>
                <input
                  type="number"
                  min="0"
                  required
                  value={formData.proPrice}
                  onChange={(e) => handleNumberChange("proPrice", e.target.value)}
                  className="h-10 w-full rounded-xl border border-border bg-background px-3 text-sm focus:border-primary focus:outline-none"
                />
              </label>

              <label className="block">
                <span className="mb-1 block text-xs font-medium text-foreground">Annual Price (BDT/year)</span>
                <input
                  type="number"
                  min="0"
                  required
                  value={formData.annualPrice}
                  onChange={(e) => handleNumberChange("annualPrice", e.target.value)}
                  className="h-10 w-full rounded-xl border border-border bg-background px-3 text-sm focus:border-primary focus:outline-none"
                />
              </label>
            </div>

            <label className="block">
              <span className="mb-1 block text-xs font-medium text-foreground">Support Email</span>
              <input
                type="email"
                required
                value={formData.supportEmail}
                onChange={(e) => setFormData((prev) => ({ ...prev, supportEmail: e.target.value }))}
                placeholder="support@example.com"
                className="h-10 w-full rounded-xl border border-border bg-background px-3 text-sm focus:border-primary focus:outline-none"
              />
              <span className="mt-1 block text-[10px] text-muted-foreground">Displayed on payment page</span>
            </label>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="inline-flex w-full items-center justify-center gap-2 rounded-xl bg-primary py-2.5 text-sm font-semibold text-white transition-all hover:bg-primary/90 disabled:opacity-50"
          >
            {isLoading ? (
              <Loader2 size={15} className="animate-spin" />
            ) : saved ? (
              <CheckCircle2 size={15} />
            ) : (
              <Save size={15} />
            )}
            {saved ? "Saved Globally!" : "Save Configuration"}
          </button>
        </form>
      )}

      {/* Security */}
      {activeSection === "security" && (
        <div className="space-y-3">
          {SECURITY_ITEMS.map((item) => (
            <div key={item.label} className="rounded-2xl border border-border/60 bg-surface p-4">
              <div className="flex items-start gap-3">
                <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-xl bg-primary/10">
                  <item.icon size={17} className="text-primary" />
                </div>
                <div>
                  <p className="text-sm font-semibold text-foreground">{item.label}</p>
                  <p className="mt-0.5 text-xs text-muted-foreground">{item.desc}</p>
                </div>
              </div>
            </div>
          ))}

          <div className="rounded-2xl border border-amber-200/60 bg-amber-50/50 p-4 dark:border-amber-700/40 dark:bg-amber-950/20">
            <div className="flex items-start gap-2">
              <Info size={14} className="mt-0.5 shrink-0 text-amber-600" />
              <div>
                <p className="text-sm font-semibold text-amber-800 dark:text-amber-400">Admin Label Required</p>
                <p className="mt-0.5 text-xs text-amber-700 dark:text-amber-500">
                  To grant admin access to a user, go to the Appwrite console → Users → select the user → Labels → add{" "}
                  <code className="rounded bg-amber-200/60 px-1 text-[10px]">admin</code>.
                </p>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Appwrite */}
      {activeSection === "appwrite" && (
        <div className="space-y-3">
          <div className="rounded-2xl border border-border/60 bg-surface p-5">
            <h3 className="text-sm font-semibold text-foreground">Appwrite Integration</h3>
            <div className="mt-3 divide-y divide-border/40">
              {[
                { label: "Project ID", value: "69c3a3f10011a71ec4dd" },
                { label: "Region", value: "SGP (Singapore) via cloud.appwrite.io" },
                { label: "Database", value: "habitwallet_main" },
                { label: "Collections", value: "users, subscriptions, admin_logs, habits, ... platform_config" },
              ].map((row) => (
                <div key={row.label} className="flex flex-col gap-0.5 py-2.5 sm:flex-row sm:items-center sm:justify-between">
                  <p className="text-xs font-medium text-muted-foreground">{row.label}</p>
                  <p className="font-mono text-xs text-foreground">{row.value}</p>
                </div>
              ))}
            </div>
          </div>

          <a
            href="https://cloud.appwrite.io/console/project-69c3a3f10011a71ec4dd"
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center justify-between rounded-2xl border border-primary/30 bg-primary/5 p-4 transition-all hover:border-primary/60"
          >
            <div className="flex items-center gap-2">
              <div className="flex h-9 w-9 items-center justify-center rounded-xl bg-primary/15">
                <ExternalLink size={16} className="text-primary" />
              </div>
              <div>
                <p className="text-sm font-semibold text-foreground">Open Appwrite Console</p>
                <p className="text-xs text-muted-foreground">Manage users, collections, and functions</p>
              </div>
            </div>
            <ChevronRight size={16} className="text-muted-foreground" />
          </a>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {
  BadgeCheck,
  Crown,
  Loader2,
  RefreshCw,
  Search,
  Shield,
  User,
  Users,
} from "lucide-react";
import { listTopProfiles } from "@/lib/profile/service";
import { useSubscriptionStore } from "@/features/subscription/store/use-subscription-store";
import type { UserProfile } from "@/lib/profile/service";

function tierBadge(tier: "free" | "pro") {
  if (tier === "pro")
    return (
      <span className="inline-flex items-center gap-1 rounded-full bg-amber-100 px-2 py-0.5 text-[9px] font-bold uppercase text-amber-700 dark:bg-amber-950/40 dark:text-amber-400">
        <Crown size={9} />
        Pro
      </span>
    );
  return (
    <span className="inline-flex items-center gap-1 rounded-full bg-border/60 px-2 py-0.5 text-[9px] font-bold uppercase text-muted-foreground">
      Free
    </span>
  );
}

function UserCard({ profile, subscriptionCount }: { profile: UserProfile; subscriptionCount: number }) {
  const initials = profile.name
    ? profile.name.split(" ").map((n) => n[0]).join("").toUpperCase().slice(0, 2)
    : profile.email.slice(0, 2).toUpperCase();

  return (
    <div className="flex items-center gap-3 rounded-xl border border-border/60 bg-surface px-4 py-3 transition-all hover:border-primary/30">
      <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-primary/15 text-sm font-bold text-primary">
        {initials}
      </div>
      <div className="min-w-0 flex-1">
        <div className="flex flex-wrap items-center gap-1.5">
          <p className="text-sm font-semibold text-foreground">{profile.name || "—"}</p>
          {tierBadge(profile.subscriptionTier)}
        </div>
        <p className="text-xs text-muted-foreground">{profile.email}</p>
        {profile.phone && <p className="text-xs text-muted-foreground">{profile.phone}</p>}
      </div>
      <div className="text-right">
        <p className="text-xs text-muted-foreground">{subscriptionCount} sub{subscriptionCount !== 1 ? "s" : ""}</p>
        {profile.subscriptionEndDate && (
          <p className="text-[10px] text-primary">until {new Date(profile.subscriptionEndDate).toLocaleDateString("en-GB")}</p>
        )}
      </div>
    </div>
  );
}

export default function AdminUsersPage() {
  const [profiles, setProfiles] = useState<UserProfile[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [tierFilter, setTierFilter] = useState<"all" | "free" | "pro">("all");
  const requests = useSubscriptionStore((state) => state.requests);
  const loadAdminRequests = useSubscriptionStore((state) => state.loadAdminRequests);

  async function fetchProfiles() {
    setIsLoading(true);
    setError(null);
    try {
      const result = await listTopProfiles(100);
      setProfiles(
        result.documents.map((doc) => {
          const d = doc as Record<string, unknown>;
          return {
            userId: String(d.userId ?? ""),
            email: String(d.email ?? ""),
            name: String(d.name ?? ""),
            phone: String(d.phone ?? ""),
            avatar: String(d.avatar ?? ""),
            country: String(d.country ?? "Bangladesh"),
            language: String(d.language ?? "en"),
            subscriptionTier: (d.subscriptionTier as "free" | "pro") ?? "free",
            subscriptionEndDate: typeof d.subscriptionEndDate === "string" ? d.subscriptionEndDate : null,
            updatedAt: String(d.updatedAt ?? ""),
          };
        })
      );
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load users.");
    } finally {
      setIsLoading(false);
    }
  }

  useEffect(() => {
    void fetchProfiles();
    void loadAdminRequests();
  }, [loadAdminRequests]);

  const filtered = profiles.filter((p) => {
    const matchesTier = tierFilter === "all" || p.subscriptionTier === tierFilter;
    const matchesSearch =
      !search ||
      p.name.toLowerCase().includes(search.toLowerCase()) ||
      p.email.toLowerCase().includes(search.toLowerCase());
    return matchesTier && matchesSearch;
  });

  const proCount = profiles.filter((p) => p.subscriptionTier === "pro").length;
  const freeCount = profiles.filter((p) => p.subscriptionTier === "free").length;

  function subscriptionCountForUser(userId: string) {
    return requests.filter((r) => r.userId === userId && r.status === "approved").length;
  }

  return (
    <div className="space-y-5 pb-10">
      {/* Header */}
      <div className="rounded-2xl border border-border/60 bg-surface p-5">
        <p className="text-[11px] uppercase tracking-[0.2em] text-muted-foreground">Admin Console</p>
        <h2 className="mt-1 text-xl font-bold text-foreground">User Management</h2>
        <p className="mt-1 text-xs text-muted-foreground">View all registered user profiles and subscription tiers.</p>

        {/* Stats */}
        <div className="mt-4 grid grid-cols-3 gap-2">
          <div className="rounded-xl bg-background p-3 text-center">
            <p className="flex items-center justify-center gap-1 text-xl font-bold text-foreground">
              <Users size={16} />
              {profiles.length}
            </p>
            <p className="text-[10px] text-muted-foreground">Total Users</p>
          </div>
          <div className="rounded-xl bg-background p-3 text-center">
            <p className="text-xl font-bold text-amber-700 dark:text-amber-400">{proCount}</p>
            <p className="text-[10px] text-muted-foreground">Pro Users</p>
          </div>
          <div className="rounded-xl bg-background p-3 text-center">
            <p className="text-xl font-bold text-muted-foreground">{freeCount}</p>
            <p className="text-[10px] text-muted-foreground">Free Users</p>
          </div>
        </div>
      </div>

      {/* Search + Filter */}
      <div className="space-y-2">
        <div className="relative">
          <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <input
            type="search"
            placeholder="Search by name or email..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="h-10 w-full rounded-xl border border-border bg-surface pl-9 pr-3 text-sm focus:border-primary focus:outline-none"
          />
        </div>
        <div className="flex items-center gap-1.5">
          {(["all", "pro", "free"] as const).map((f) => (
            <button
              key={f}
              type="button"
              onClick={() => setTierFilter(f)}
              className={`rounded-lg px-3 py-1 text-xs font-medium capitalize transition-all ${
                tierFilter === f
                  ? "bg-primary text-white"
                  : "border border-border/60 text-muted-foreground hover:bg-surface hover:text-foreground"
              }`}
            >
              {f === "all" ? "All tiers" : `${f.charAt(0).toUpperCase() + f.slice(1)} only`}
            </button>
          ))}
          <button
            type="button"
            onClick={() => void fetchProfiles()}
            className="ml-auto inline-flex items-center gap-1 rounded-lg border border-border/60 px-2.5 py-1 text-xs text-muted-foreground hover:bg-surface"
          >
            <RefreshCw size={11} />
            Refresh
          </button>
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className="rounded-xl border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700 dark:border-red-800/50 dark:bg-red-950/40 dark:text-red-400">
          {error}
          <br />
          <button className="mt-1 font-semibold underline" onClick={() => void fetchProfiles()}>Retry</button>
        </div>
      )}

      {/* User List */}
      <div className="space-y-2">
        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 size={20} className="animate-spin text-muted-foreground" />
          </div>
        ) : filtered.length === 0 ? (
          <div className="rounded-2xl border border-border/60 py-12 text-center">
            <User size={30} className="mx-auto text-muted-foreground/40" />
            <p className="mt-2 text-sm text-muted-foreground">
              {search || tierFilter !== "all" ? "No users match your search." : "No users found."}
            </p>
          </div>
        ) : (
          filtered.map((profile) => (
            <UserCard
              key={profile.userId}
              profile={profile}
              subscriptionCount={subscriptionCountForUser(profile.userId)}
            />
          ))
        )}
      </div>

      {/* Info Banner */}
      <div className="rounded-xl border border-border/60 bg-surface p-4">
        <div className="flex items-start gap-2">
          <Shield size={14} className="mt-0.5 shrink-0 text-muted-foreground" />
          <p className="text-xs text-muted-foreground">
            User data is fetched from Appwrite users collection. Subscription tier changes happen automatically when
            you approve or reject payment requests in the{" "}
            <a href="/admin/subscriptions" className="font-medium text-primary hover:underline">
              Subscriptions
            </a>{" "}
            section.
          </p>
        </div>
      </div>
    </div>
  );
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import {
  BadgeCheck,
  CheckCircle2,
  ChevronRight,
  Clock3,
  Copy,
  Crown,
  ExternalLink,
  Info,
  Loader2,
  ShieldAlert,
  Smartphone,
  Wallet,
  XCircle,
  Zap,
} from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { useSubscriptionStore } from "@/features/subscription/store/use-subscription-store";
import { getStoredUserSession } from "@/lib/storage/session";
import { useConfigStore } from "@/lib/config/use-config-store";

const subscriptionSchema = z.object({
  months: z.coerce.number().min(1).max(12),
  amount: z.coerce.number().min(1),
  senderNumber: z.string().min(11).max(14),
  transactionId: z.string().min(6).max(64),
});

type SubscriptionValues = z.input<typeof subscriptionSchema>;

const FREE_FEATURES = [
  "Unlimited habit tracking",
  "Unlimited finance tracking",
  "Basic analytics",
  "Local storage (offline-first)",
  "Light & dark theme",
];

const PRO_FEATURES = [
  "Everything in Free",
  "Cloud sync across devices",
  "Export to PDF & CSV",
  "Advanced analytics & insights",
  "Unlimited custom categories",
  "Priority support",
  "Habit reminder notifications",
  "Budget forecasting",
];

// BKASH_STEPS moved inside component hook

function statusConfig(status: "pending" | "approved" | "rejected") {
  if (status === "approved")
    return {
      color: "text-emerald-700 dark:text-emerald-400",
      bg: "bg-emerald-50 dark:bg-emerald-950/40 border-emerald-200 dark:border-emerald-800/50",
      icon: CheckCircle2,
      label: "Approved",
    };
  if (status === "rejected")
    return {
      color: "text-red-700 dark:text-red-400",
      bg: "bg-red-50 dark:bg-red-950/40 border-red-200 dark:border-red-800/50",
      icon: XCircle,
      label: "Rejected",
    };
  return {
    color: "text-amber-700 dark:text-amber-400",
    bg: "bg-amber-50 dark:bg-amber-950/40 border-amber-200 dark:border-amber-800/50",
    icon: Clock3,
    label: "Pending Review",
  };
}

type PlanCardProps = {
  name: string;
  price: string;
  period: string;
  features: string[];
  isActive: boolean;
  isPro?: boolean;
