                      💬 {request.adminNote}
                    </p>
                  )}
                </li>
              );
            })}
          </ul>
        </article>
      )}

      {/* Help */}
      <article className="rounded-[2rem] border border-border/80 bg-surface p-5 shadow-[var(--soft-shadow)]">
