          href={`mailto:${config.supportEmail}`}
          className="mt-3 inline-flex items-center gap-1.5 text-xs font-medium text-primary hover:underline"
        >
          <ExternalLink size={11} />
          {config.supportEmail}
        </a>
      </article>
    </section>
  );
}

import { ID } from "appwrite";
import { databases } from "./appwrite";
import { appwriteEnv } from "./env";

export type PlatformConfig = {
  bkashNumber: string;
  proPrice: number;
  annualPrice: number;
  supportEmail: string;
};

export const DEFAULT_CONFIG: PlatformConfig = {
  bkashNumber: "01XXXXXXXXX",
  proPrice: 199,
  annualPrice: 1799,
  supportEmail: "support@habitwallet.app",
};

// We assume there's a collection 'platform_config' with a document ID 'global'
// For production, create a collection named 'platform_config' with a String attribute 'data'
const CONFIG_DOC_ID = "global";

export async function fetchPlatformConfig(): Promise<PlatformConfig> {
  const collectionId = process.env.NEXT_PUBLIC_APPWRITE_PLATFORM_CONFIG_COLLECTION_ID || "platform_config";

  if (!appwriteEnv.databaseId) return DEFAULT_CONFIG;

  try {
    const doc = await databases.getDocument(
      appwriteEnv.databaseId,
      collectionId,
      CONFIG_DOC_ID
    );

    // Parse the JSON data safely
    if (doc.data) {
      const parsed = JSON.parse(doc.data as string);
      return { ...DEFAULT_CONFIG, ...parsed };
    }
    return DEFAULT_CONFIG;
  } catch (error: any) {
    // If collection/document doesn't exist, return default safely
    console.warn("Could not fetch platform config:", error.message);
    return DEFAULT_CONFIG;
  }
}

export async function updatePlatformConfig(config: PlatformConfig) {
  const collectionId = process.env.NEXT_PUBLIC_APPWRITE_PLATFORM_CONFIG_COLLECTION_ID || "platform_config";

  if (!appwriteEnv.databaseId) throw new Error("Database not configured");

  try {
    // Try to update existing
    await databases.updateDocument(
      appwriteEnv.databaseId,
      collectionId,
      CONFIG_DOC_ID,
      { data: JSON.stringify(config) }
    );
  } catch (error: any) {
    if (error.code === 404) {
      // Create if it doesn't exist
      await databases.createDocument(
        appwriteEnv.databaseId,
        collectionId,
        CONFIG_DOC_ID,
        { data: JSON.stringify(config) }
      );
    } else {
      throw error;
    }
  }
}

import { create } from "zustand";
import { fetchPlatformConfig, updatePlatformConfig, PlatformConfig, DEFAULT_CONFIG } from "@/lib/config/platform-service";

type ConfigStore = {
  config: PlatformConfig;
  isLoading: boolean;
  error: string | null;
  loadConfig: () => Promise<void>;
  saveConfig: (newConfig: PlatformConfig) => Promise<void>;
};

export const useConfigStore = create<ConfigStore>((set, get) => ({
  config: DEFAULT_CONFIG,
  isLoading: false,
  error: null,

  loadConfig: async () => {
    set({ isLoading: true, error: null });
    try {
      const config = await fetchPlatformConfig();
      set({ config, isLoading: false });
    } catch (e: any) {
      set({ error: e.message || "Failed to load config", isLoading: false });
    }
  },

  saveConfig: async (newConfig: PlatformConfig) => {
    set({ isLoading: true, error: null });
    try {
      await updatePlatformConfig(newConfig);
      set({ config: newConfig, isLoading: false });
    } catch (e: any) {
      set({ 
        error: e.message?.includes("not found") 
          ? "Storage collection 'platform_config' not created in Appwrite." 
          : "Failed to save config: " + e.message, 
        isLoading: false 
      });
      throw e;
    }
  },
}));
